SELECT order_no
FROM ORDERS
WHERE order_content = #{content}
AND student_id = #{studentId}
AND stock_no = #{stockNo}
AND order_state = #{state}
AND amount = #{amount}
AND order_point = #{price}
ORDER BY order_date DESC
LIMIT 1

